+fn runtime_hostcall_is_secret_env_key(key: &str) -> bool {
+    let upper = key.to_ascii_uppercase();
+    let needles = [
+        "SECRET",
+        "TOKEN",
+        "PASSWORD",
+        "PASSWD",
+        "AUTH",
+        "COOKIE",
+        "SESSION",
+        "PRIVATE",
+        "KEY",
+        "AWS_",
+        "OPENAI_",
+        "ANTHROPIC_",
+    ];
+    needles.iter().any(|needle| upper.contains(needle))
+}
